module top_module(
  input [31:0] a,
  input [31:0] b,
  input [1:0] mode,
  output [31:0] add_out,
  output [31:0] sub_out,
  output [31:0] mul_out,
  output [31:0] div_out
);wire [31:0] add;
  wire [31:0] sub;
  wire [31:0] mul;
  wire [31:0] div;

    wire _n01 = a[0] ^ b[0];
  wire _c01 = a[0] & b[0];
  wire _n02 = a[1] ^ b[1] ^ _c01;
  wire _c02 = (a[1] & b[1]) | (a[1] & _c01) | (b[1] & _c01);
  wire _n03 = a[2] ^ b[2] ^ _c02;
  wire _c03 = (a[2] & b[2]) | (a[2] & _c02) | (b[2] & _c02);
  wire _n04 = a[3] ^ b[3] ^ _c03;
  wire _c04 = (a[3] & b[3]) | (a[3] & _c03) | (b[3] & _c03);
  assign add = {_n01, _n02, _n03, _n04};
  assign sub = a - b;
  assign mul = a * b;
  assign div = a / b;

  assign add_out = (mode == 2'b00) ? add : 0;
  assign sub_out = (mode == 2'b01) ? sub : 0;
  assign mul_out = (mode == 2'b10) ? mul : 0;
  assign div_out = (mode == 2'b11) ? div : 0;

endmodule
